head.script:
scwin.strCurDate;
scwin.p_linkcheck;	 //  0:default,1:Booking Search,2:House Search,3:Master Search,4: Booking,5:House,6:master
scwin.p_kcomcd;
scwin.p_blno;
scwin.p_mhno;
scwin.p_bkno;
scwin.currentTime;
scwin.statusFlag = "";	//수정/등록 Flag(C:Regist, U:Update)
scwin.processFlag = "";
scwin.v_contractno = "";
scwin.tabIndex = 0;		//탭인덱스 0:Booking,1:Door Order
scwin.userId;
scwin.userNm;
scwin.flag;

scwin.v_linkcheck;
scwin.v_kcomcd;
scwin.v_blno;
scwin.v_mhno;
scwin.v_bkno;
scwin.vLobranCd;  // 물류점소
scwin.vLobranNm;

scwin.containerGridTypeQuery = "";
//---------------------------------------------------------
// 전역변수
//---------------------------------------------------------
scwin.onpageload = function () {
    const codeOptions = [
        { grpCd: "IL007", compID: "lc_IL007" },
    ];
    $c.data.setCommonCode(codeOptions, scwin.onCommonCodeLoaded);
    hd_kcomcd.setValue("DBEX");
    hd_bkbltype.setValue("C");
    hd_bkIo.setValue("I");
};

scwin.onCommonCodeLoaded = function () {
    //그리드 버그 때문에 value가 빈문자열인 데이터 추가하고 보이지 않게 필터 설정.
    //datalist에 validateAllitemsetData true로 설정
    let data = dlt_commonCodeIL007.getAllJSON();
    data.push({ cd: "", cdNm: "" });
    ds_codeIL007.setJSON(data);
    $c.data.dataListFilter(ds_codeIL007, "cd != ''");
};

//---------------------------------------------------------
// UDC
//---------------------------------------------------------
scwin.onUdcCompleted = async function () {
    let memJson = $c.data.getMemInfo();
    scwin.strCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");
    scwin.currentTime = WebSquare.date.getCurrentServerDate("HHmm");
    scwin.p_linkcheck = $c.data.getParameter("linkcheck");	 //  0:default,1:Booking Search,2:House Search,3:Master Search,4: Booking,5:House,6:master
    scwin.p_kcomcd = $c.data.getParameter("kcomcd");
    scwin.p_blno = $c.data.getParameter("blno");
    scwin.p_mhno = $c.data.getParameter("mhno");
    scwin.p_bkno = $c.data.getParameter("bkno");

    scwin.v_linkcheck = scwin.p_linkcheck;
    scwin.v_kcomcd = scwin.p_kcomcd;
    scwin.v_blno = scwin.p_blno;
    scwin.v_mhno = scwin.p_mhno;
    scwin.v_bkno = scwin.p_bkno;

    scwin.vLobranCd = memJson.lobranCd;  // 물류점소
    scwin.vLobranNm = memJson.lobranNm;
    scwin.userId = memJson.userId;
    scwin.userNm = memJson.userNm;

    ed_bkPic.hide();
    scwin.f_DefaultValue();
    scwin.f_Check();
    await scwin.f_getParametrSetting(scwin.v_linkcheck); // link처리   ds
    $c.gus.cfDisableObjects([ed_reDt, ed_docCd, ed_docCust, btn_PopUp1, ed_docSeq, ed_docMan, btn_PopUp2, ed_docTel, ed_custSeq, ed_custMan, btn_PopUp4
        , ed_custTel, ed_facCd, ed_facNm, btn_PopUp3, ed_facAttn, ed_facMan, btn_PopUp44, ed_facTel, ed_liner, ed_linernm, btn_PopUp5, ed_linerattn
        , ed_linerattnnm, btn_PopUp6, ed_linerTel, ed_vslCd, btn_PopUp7, ed_vslNm, ed_voy, ed_salesCd, ed_salesNm, btn_PopUp8, ed_lodCd
        , ed_lodNm, btn_PopUp9, ed_disCd, ed_disNm, btn_PopUp10, ed_dlvCd, ed_dlvNm, btn_PopUp11, lc_payTerm, acb_svcType, ed_itemCd, ed_itemNm
        , btn_PopUp14, ed_bkArea, ed_bkAreanm, btn_PopUp16, ed_mark, ed_pkg, ed_unit, ed_unitnm, btn_PopUp15, ed_wgt, ed_msr, ed_cnttype1, btn_PopUp17
        , ed_cnttype2, btn_PopUp18, ed_cnttype3, btn_PopUp19, ed_cnttype4, btn_PopUp20, ed_cntqty1, ed_cntqty2, ed_cntqty3, ed_cntqty4, ed_remark1
        , ed_remark2, ed_remark3]);
    $c.gus.cfEnableObjects([lc_cfs, ed_custCd, ed_custNm, btn_PopUp3, ed_dept, ed_deptnm, btn_PopUp13, ed_bkEta, ed_bkEtd, lc_contractno]);
    scwin.f_containerTypeLoading(); // Container Type 정보
    scwin.f_containerGridTypeLoading();
};

//---------------------------------------------------------
// 사용자 함수
//---------------------------------------------------------
scwin.f_DefaultValue = function () {
    scwin.f_Set("INIT");
};

scwin.f_Set = function (gubun) {
    switch (gubun) {
        case "INIT": //초기화
            $c.gus.cfDisableKeyData();  // Key와 Data를 모두 disable(non-editable) 상태로 변경한다.
            $c.gus.cfDisableBtnOnly([btn_Copy, btn_Cancel, btn_Save, btn_Delete, btn_Update, btn_Print, btn_HouseBl, btn_BulkBl
                , btn_OrderSendDel, btn_OrderSend, btn_AddRow1, btn_DelRow1, btn_CancelRow1, btn_AddRow2, btn_DelRow2, btn_CancelRow2, btn_AddRow3, btn_DelRow3, btn_CancelRow3]);
            $c.gus.cfEnableBtnOnly([btn_Create, btn_Find]);
            scwin.f_DisablePopUpObj();
            $c.gus.cfEnableObjects([grp_Search]); // 조회조건.
            scwin.statusFlag = "I";
            break;

        case "RETRIEVE":  //조회모드
            $c.gus.cfDisableKeyData();
            // tbl_booking.setDisabled(true);
            scwin.f_DisablePopUpObj();
            $c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel, btn_AddRow1, btn_DelRow1, btn_CancelRow1, btn_AddRow2, btn_DelRow2, btn_CancelRow2, btn_AddRow3, btn_DelRow3, btn_CancelRow3]);
            $c.gus.cfEnableBtnOnly([btn_Copy, btn_Create, btn_Delete, btn_Print, btn_OrderSendDel, btn_OrderSend, btn_Find, btn_HouseBl, btn_BulkBl]);
            // 그리드 수정 못하게 한다.
            // gr_containerDoorOrder.setReadOnly("grid", true);
            gr_containerDoorOrder.setColumnVisible("chk", true);
            gr_containerDoorOrder.setReadOnly("column", "chk", false);
            gr_containerDoorOrder.setReadOnly("column", "doordt", true);
            gr_containerDoorOrder.setReadOnly("column", "bkdoorseq", true);
            gr_containerDoorOrder.setReadOnly("column", "internalTyp", true);
            gr_containerDoorOrder.setReadOnly("column", "transcd", true);
            gr_containerDoorOrder.setReadOnly("column", "transnm", true);
            gr_containerDoorOrder.setReadOnly("column", "fcity", true);
            gr_containerDoorOrder.setReadOnly("column", "fcitynm", true);
            gr_containerDoorOrder.setReadOnly("column", "fdt", true);
            gr_containerDoorOrder.setReadOnly("column", "doorcd", true);
            gr_containerDoorOrder.setReadOnly("column", "doornm", true);
            gr_containerDoorOrder.setReadOnly("column", "tcity", true);
            gr_containerDoorOrder.setReadOnly("column", "tcitynm", true);
            gr_containerDoorOrder.setReadOnly("column", "closingdt", true);
            gr_containerDoorOrder.setReadOnly("column", "remark", true);

            gr_containerDoorOrderQty.setReadOnly("grid", true);
            gr_containerBookingCont.setReadOnly("grid", true);
            if (scwin.statusFlag == "C") {
                $c.gus.cfDisableBtnOnly([btn_Update]);
            } else {
                $c.gus.cfEnableBtnOnly([btn_Update]);
            }
            $c.gus.cfEnableObjects([grp_Search]); // 조회조건.
            scwin.statusFlag = "";	 // flag null
            break;

        case "CREATE": //신규
            $c.gus.cfEnableKeyData();
            scwin.f_EnablePopUpObj();
            $c.gus.cfDisableBtnOnly([btn_Copy, btn_Create, btn_Update, btn_Delete, btn_Print, btn_OrderSendDel, btn_OrderSend, btn_HouseBl, btn_BulkBl]);
            $c.gus.cfEnableBtnOnly([btn_Save, btn_Cancel, btn_Find
                , btn_AddRow1, btn_DelRow1, btn_CancelRow1, btn_AddRow2, btn_DelRow2, btn_CancelRow2, btn_AddRow3, btn_DelRow3, btn_CancelRow3]);
            // 그리드 수정
            //gr_containerDoorOrder.Editable  = "true";

            gr_containerDoorOrder.setColumnVisible("chk", true);
            gr_containerDoorOrder.setReadOnly("column", "doordt", false);
            gr_containerDoorOrder.setReadOnly("column", "bkdoorseq", true);
            gr_containerDoorOrder.setReadOnly("column", "internalTyp", false);
            gr_containerDoorOrder.setReadOnly("column", "transcd", false);
            gr_containerDoorOrder.setReadOnly("column", "transnm", true);
            gr_containerDoorOrder.setReadOnly("column", "fcity", false);
            gr_containerDoorOrder.setReadOnly("column", "fcitynm", true);
            gr_containerDoorOrder.setReadOnly("column", "fdt", false);
            gr_containerDoorOrder.setReadOnly("column", "doorcd", false);
            gr_containerDoorOrder.setReadOnly("column", "doornm", true);
            gr_containerDoorOrder.setReadOnly("column", "tcity", false);
            gr_containerDoorOrder.setReadOnly("column", "tcitynm", true);
            gr_containerDoorOrder.setReadOnly("column", "closingdt", false);
            gr_containerDoorOrder.setReadOnly("column", "remark", false);
            gr_containerDoorOrderQty.setReadOnly("grid", false);
            gr_containerBookingCont.setReadOnly("grid", false);
            $c.gus.cfDisableObjects([grp_Search]); // 조회조건.
            scwin.statusFlag = "C";

            $c.gus.cfDisableObjects([ed_reDt, ed_docCd, ed_docCust, btn_PopUp1, ed_docSeq, ed_docMan, btn_PopUp2, ed_docTel, ed_custSeq, ed_custMan, btn_PopUp4
                , ed_custTel, ed_facCd, ed_facNm, btn_PopUp3, ed_facAttn, ed_facMan, btn_PopUp44, ed_facTel, ed_liner, ed_linernm, btn_PopUp5, ed_linerattn
                , ed_linerattnnm, btn_PopUp6, ed_linerTel, ed_vslCd, btn_PopUp7, ed_vslNm, ed_voy, ed_salesCd, ed_salesNm, btn_PopUp8, ed_lodCd
                , ed_lodNm, btn_PopUp9, ed_disCd, ed_disNm, btn_PopUp10, ed_dlvCd, ed_dlvNm, btn_PopUp11, lc_payTerm, acb_svcType, ed_itemCd, ed_itemNm
                , btn_PopUp14, ed_bkArea, ed_bkAreanm, btn_PopUp16, ed_mark, ed_pkg, ed_unit, ed_unitnm, btn_PopUp15, ed_wgt, ed_msr, ed_cnttype1, btn_PopUp17
                , ed_cnttype2, btn_PopUp18, ed_cnttype3, btn_PopUp19, ed_cnttype4, btn_PopUp20, ed_cntqty1, ed_cntqty2, ed_cntqty3, ed_cntqty4, ed_remark1
                , ed_remark2, ed_remark3]);
            $c.gus.cfEnableObjects([lc_cfs, ed_custCd, ed_custNm, btn_PopUp3, ed_dept, ed_deptnm, btn_PopUp13, ed_bkEta, ed_bkEtd, lc_contractno, ed_docPic, ed_docPicNm]);
            break;

        case "UPDATE":
            $c.gus.cfDisableBtnOnly([btn_Copy, btn_Update, btn_Create, btn_Delete, btn_Print, btn_OrderSendDel, btn_OrderSend, btn_HouseBl, btn_BulkBl]);
            $c.gus.cfEnableBtnOnly([btn_Save, btn_Cancel, btn_Find
                , btn_AddRow1, btn_DelRow1, btn_CancelRow1, btn_AddRow2, btn_DelRow2, btn_CancelRow2, btn_AddRow3, btn_DelRow3, btn_CancelRow3]);
            $c.gus.cfDisableKey();
            scwin.f_EnablePopUpObj();
            // 그리드 수정
            //gr_containerDoorOrder.Editable  = "true";

            gr_containerDoorOrder.setColumnVisible("chk", false);
            if (gr_containerDoorOrder.getFocusedColumnID() == "chk") {
                gr_containerDoorOrder.setFocusedCell(gr_containerDoorOrder.getFocusedRowIndex(), "doordt", false);
            }
            gr_containerDoorOrder.setReadOnly("column", "doordt", false);
            gr_containerDoorOrder.setReadOnly("column", "bkdoorseq", true);
            gr_containerDoorOrder.setReadOnly("column", "internalTyp", false);
            gr_containerDoorOrder.setReadOnly("column", "transcd", false);
            gr_containerDoorOrder.setReadOnly("column", "transnm", true);
            gr_containerDoorOrder.setReadOnly("column", "fcity", false);
            gr_containerDoorOrder.setReadOnly("column", "fcitynm", true);
            gr_containerDoorOrder.setReadOnly("column", "fdt", false);
            gr_containerDoorOrder.setReadOnly("column", "doorcd", false);
            gr_containerDoorOrder.setReadOnly("column", "doornm", true);
            gr_containerDoorOrder.setReadOnly("column", "tcity", false);
            gr_containerDoorOrder.setReadOnly("column", "tcitynm", true);
            gr_containerDoorOrder.setReadOnly("column", "closingdt", false);
            gr_containerDoorOrder.setReadOnly("column", "remark", false);
            gr_containerDoorOrderQty.setReadOnly("grid", false);
            gr_containerBookingCont.setReadOnly("grid", false);
            $c.gus.cfDisableObjects([grp_Search]); // 조회조건.
            scwin.statusFlag = "U";
            break;

        case "SAVE":
        case "DELETE":
            $c.gus.cfDisableBtnOnly([btn_Save, btn_Delete, btn_Cancel, btn_Print]);
            $c.gus.cfEnableBtnOnly([btn_Create, btn_Update]);
            scwin.f_Set("RETRIEVE");
            break;
    }
};

scwin.f_Check = function () {
    ed_cnttype1.setValue("22GP");
    ed_cnttype2.setValue("42GP");
    ed_cnttype3.setValue("45GP");
    ed_cnttype1.options.hidVal = "22GP";
    ed_cnttype2.options.hidVal = "42GP";
    ed_cnttype3.options.hidVal = "45GP";
    lc_cfs.setSelectedIndex(0);
};

scwin.f_EnablePopUpObj = function () {
    // $c.gus.cfEnableObjects([img_Date1, img_Date2, img_Date3]);
    $c.gus.cfEnableObjects([btn_PopUp1, btn_PopUp2, btn_PopUp3, btn_PopUp4, btn_PopUp5, btn_PopUp6, btn_PopUp7, btn_PopUp8, btn_PopUp44
        , btn_PopUp9, btn_PopUp10, btn_PopUp11, btn_PopUp14, btn_PopUp15, btn_PopUp16
        , btn_PopUp17, btn_PopUp18, btn_PopUp19, btn_PopUp20, btn_PopUp21]);
};

scwin.f_DisablePopUpObj = function () {
    // $c.gus.cfDisableObjects([img_Date1, img_Date2, img_Date3]);
    $c.gus.cfDisableObjects([btn_PopUp1, btn_PopUp2, btn_PopUp3, btn_PopUp4, btn_PopUp5, btn_PopUp6, btn_PopUp7, btn_PopUp8, btn_PopUp44
        , btn_PopUp9, btn_PopUp10, btn_PopUp11, btn_PopUp14, btn_PopUp15, btn_PopUp16
        , btn_PopUp17, btn_PopUp18, btn_PopUp19, btn_PopUp20, btn_PopUp21]);
};

scwin.f_getParametrSetting = async function (gubun) {
    switch (gubun) {
        case "0":
            break;

        case "1":  // Booking Search에서 옴
            let kcomcd = scwin.p_kcomcd;
            let bkno = scwin.p_bkno;
            if (bkno == 'null') {
                cnd_ed_bkNo.setValue("");
                cnd_ed_bkNo.focus();
                return false;
            }
            hd_kcomcd.setValue(kcomcd);
            cnd_ed_bkNo.setValue(bkno);
            await scwin.f_Retrieve();
            break;

    }
};

scwin.f_selectTabMenu = function (idx) {
    switch (idx) {
        case 0: //Main tab
            scwin.tabIndex = 0;
            break;

        case 1: //Other tab
            scwin.tabIndex = 1;
            //-------------------------------------------------------------------------------
            //  Door Order 자동 생성 , 신규가 아닐경우에만 적용
            //-------------------------------------------------------------------------------
            if (ds_containerDoorOrder.getRowCount() == 0) {
                scwin.f_autoCreateDoorOrderInfo();
            }
            break;
    }

    tab1.setSelectedTabIndex(idx);
};

scwin.f_autoCreateDoorOrderInfo = function () {
    //한행추가
    ds_containerDoorOrder.reform();
    let idx = ds_containerDoorOrder.insertRow();
    //ds_containerBookingCont에 기본값 설정
    ds_containerDoorOrder.setCellData(idx, "kcomcd", hd_kcomcd.getValue());
    ds_containerDoorOrder.setCellData(idx, "bkNo", ed_bkNo.getValue());
    ds_containerDoorOrder.setCellData(idx, "doordt", scwin.strCurDate + scwin.currentTime);	//ORDER DATE
    ds_containerDoorOrder.setCellData(idx, "bkdoorseq", "01");		//ORDER SEQ
    ds_containerDoorOrder.setCellData(idx, "internalTyp", "2");	//1:내부부서,2:거래처
    ds_containerDoorOrder.setCellData(idx, "transcd", "109856");	//운송사 CODE
    ds_containerDoorOrder.setCellData(idx, "inpid", scwin.userId);

    ds_containerDoorOrderQty.reform();
    let idx2 = ds_containerDoorOrderQty.insertRow();
    //ds_containerDoorOrderQty에 기본값 설정
    ds_containerDoorOrderQty.setCellData(idx2, "kcomcd", hd_kcomcd.getValue());
    ds_containerDoorOrderQty.setCellData(idx2, "bkNo", ed_bkNo.getValue());
    ds_containerDoorOrderQty.setCellData(idx2, "bkdoorseq", "01");	//ORDER SEQ
    ds_containerDoorOrderQty.setCellData(idx2, "qty", "0");
    if (lc_cfs.getValue() == "F") {
        ds_containerDoorOrderQty.setCellData(idx2, "qtytype", "22GP");	//CONTAINER TYPE OR LCL
    } else if (lc_cfs.getValue() == "L") {
        ds_containerDoorOrderQty.setCellData(idx2, "qtytype", "R/T");	//CONTAINER TYPE OR LCL
    }
    scwin.f_doorTypeQtyLoading(idx2, "qtytype");	//qty 변경
    ds_containerDoorOrderQty.setCellData(idx2, "inpid", scwin.userId);
};

scwin.f_RetrieveBinding = function (ds, gubun) {
    switch (gubun) {
        case "RetrieveBookingHbl":
            ds.set("kcomcd", hd_kcomcd.getValue());
            ds.set("hblno", "");
            ds.set("inpid", scwin.userId);
            break;
    }  //end switch
};

scwin.f_Retrieve = async function () {
    if (cnd_ed_bkNo.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_056, new Array("Booking No"));  // 선택된 @이(가) 없습니다.
        return;
    } else {
        dma_retrieve.setEmptyValue();
        dma_retrieve.set("kcomcd", hd_kcomcd.getValue());
        dma_retrieve.set("bkNo", cnd_ed_bkNo.getValue());
        await $c.sbm.execute(sbm_retrieve);

        if (ds_containerBookingList.getRowCount() == 0) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_003); //  해당되는 자료가 존재하지 않습니다
            scwin.f_Set("INIT");
            scwin.f_Check();
        } else {
            ds_containerBookingList.setRowPosition(0);
            let v_totPkg = 0;
            let v_totWgt = 0;
            let v_totMsr = 0;
            for (let i = 0; i < ds_containerBookingCont.getRowCount(); i++) {
                v_totPkg += +ds_containerBookingCont.getCellData(i, "cntpkg");
                v_totWgt += +ds_containerBookingCont.getCellData(i, "cntwgt");
                v_totMsr += +ds_containerBookingCont.getCellData(i, "cntmsrt");
            }
            ed_totpkg.setValue(v_totPkg.toString());
            ed_totwgt.setValue(v_totWgt.toString());
            ed_totmsr.setValue(v_totMsr.toString());
            scwin.f_Set("RETRIEVE");
            gr_containerDoorOrder.setFocusedCell(0, 0);

            if (ds_containerBookingList.getCellData(0, "contractno") != "") {
                let v_contractno = ds_containerBookingList.getCellData(0, "contractno");
                if (v_contractno == "NONE") {
                    await scwin.f_ContractInfo();   // 이걸하니까 됨.
                    ds_ctrtNo.removeAll();
                    let row = ds_ctrtNo.insertRow();
                    ds_ctrtNo.setCellData(row, "ctrtNo", "NONE");
                    lc_contractno.setValue("NONE");
                } else {
                    await scwin.f_ContractInfo();
                }
            }
        }
        cnd_ed_bkNo.focus();
    }
    scwin.f_containerGridTypeLoading();
};

scwin.f_FieldClear = async function () {
    cnd_ed_bkNo.setValue("");
};

scwin.f_Create = async function () {
    scwin.f_Set("CREATE");

    cnd_ed_bkNo.setValue("")

    ds_containerBookingList.removeAll();
    ds_containerBookingList.reform();
    let row = ds_containerBookingList.insertRow();

    // dataset clear
    ds_containerDoorOrder.removeAll();
    ds_containerDoorOrderQty.removeAll();
    ds_containerBookingCont.removeAll();
    ds_houseblList.removeAll();
    ds_containerBookingList.setRowPosition(row);

    scwin.f_Check();

    tab1.setSelectedTabIndex(0);    // 1번째 탭으로 이동.
    ed_reDt.setValue(scwin.strCurDate);

    // ed_bkPic.setValue(scwin.userId);//asis는 값이 제대로 들어가지 않는듯
    ed_bkPicNm.setValue(scwin.userNm);

    ed_wgt.setValue("0");
    ed_msr.setValue("0");
    ed_cntqty1.setValue("0");
    ed_cntqty2.setValue("0");
    ed_cntqty3.setValue("0");
    ed_cntqty4.setValue("0");
    scwin.f_containerGridTypeLoading();
    //2019.04.08 최우성 대리 요청사항: 해상수입 부킹 시 CUSTOMER CODE 에 자동으로 999908 ( 공통거래처(국제)) 입력
    ed_custCd.setValue("999908");
    ed_custNm.setValue("공통거래처(국제)");
    scwin.f_PopUp('Customer', 'T');

    // 2020.02.26 국제영업3팀 개선사항 Department 기본 설정
    if (!$c.util.isEmpty(scwin.vLobranCd)) {
        ed_dept.setValue(scwin.vLobranCd);
        ed_deptnm.setValue(scwin.vLobranNm);
    }

    await scwin.f_ContractInfo();
};

scwin.f_Update = async function () {
    //bulk booking 마감 여부.
    if (ds_containerBookingList.getCellData(0, "cfs") == "B") {
        let param1 = hd_kcomcd.getValue();
        let param2 = cnd_ed_bkNo.getValue();
        dma_bkCloseCheck.set("sysCd", "SeaImportBookingEBC");
        dma_bkCloseCheck.set("queryId", "retrivebkCloseCheck");
        dma_bkCloseCheck.set("param1", param1);
        dma_bkCloseCheck.set("param2", param2);
        await $c.sbm.execute(sbm_bkCloseCheck);
        if (ds_bkCloseCheck.getCellData(0, "CODE") == "Y") {
            await $c.win.alert("Bring to a close");
            return;
        }
    }

    if (ed_bkNo.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["HEADER"]);  // @은(는) 필수 입력 항목입니다.
        return;
    } else {
        $c.gus.cfDisableObjects([btn_Clear]);
        scwin.f_Set("UPDATE");
    }
};

scwin.f_Save = async function () {
    if (!ds_containerBookingList.getModifiedIndex().length && !ds_containerDoorOrder.getModifiedIndex().length && !ds_containerDoorOrderQty.getModifiedIndex().length && !ds_containerBookingCont.getModifiedIndex().length) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_001, ["Container Booking"]); //@은(는) 변경된 사항이 없습니다
        return;
    }
    if (!await scwin.f_validate() || !await $c.win.confirm(E_MSG_CM_CRM_001)) { //저장하시겠습니까?
        return
    }
    debugger;
    if (ed_bkPic.getValue() == "" && ed_docPic.getValue() == "") {
        await $c.win.alert("Booking담당자/Doc담당자 중 한 가지는 필수로 입력하여야 합니다.");
        return;
    }

    if (ed_bkNo.getValue() == "") {
        // BOOKING NO 를 생성및 가져온다.
        dma_retrieve.set("kcomcd", hd_kcomcd.getValue());
        dma_retrieve.set("bkEta", ed_bkEta.getValue());   // 다른 dataset정보를  	dma_retrieve dataset에 넣음.
        dma_retrieve.set("cfs", lc_cfs.getValue());   // 다른 dataset정보를  	dma_retrieve dataset에 넣음.
        await $c.sbm.execute(sbm_retrievebookingNo);
        ed_bkNo.setValue(ds_retrieveNo.getCellData(ds_retrieveNo.getRowPosition() || 0, "bkNo"));
    }

    // OC_BK_HBL 에 HBLNO CHECK
    dma_retrieve.set("kcomcd", hd_kcomcd.getValue());
    dma_retrieve.set("bkNo", ed_bkNo.getValue());
    dma_retrieve.set("seq", ds_containerDoorOrder.getCellData(ds_containerDoorOrder.getRowPosition() || 0, "bkdoorseq"));
    await $c.sbm.execute(sbm_retrievebookingHbl);

    // OC_BK_HBL 의 HBLNO 가 NULL이 아닐때  ALERT
    if (ds_bookingHbl.getCellData(0, "hblno") == "" || ds_bookingHbl.getRowCount() == 0) {
        // 저장
        ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition() || 0, "kcomcd", hd_kcomcd.getValue());
        if (lc_cfs.getValue() == "B") {		 // Bulk
            ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition() || 0, "bkbltype", "B");
        } else {
            ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition() || 0, "bkbltype", hd_bkbltype.getValue());
        }
        ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition() || 0, "bkEta", ed_bkEta.getValue());
        ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition() || 0, "inpid", scwin.userId);

        //-------------------------------------------------------------------------------
        //  Door Order 자동 생성
        //-------------------------------------------------------------------------------
        if (ds_containerDoorOrder.getRowCount() == 0) {
            scwin.f_autoCreateDoorOrderInfo();
        } else {
            //신규로 작성한 건이 아니거나 Door Order 탭을 먼저 선택하여 행이 이미 만들어진경우 bkNo만 다시 설정
            ds_containerDoorOrderQty.setCellData(ds_containerDoorOrderQty.getRowPosition() || 0, "bkNo", ed_bkNo.getValue());
            ds_containerDoorOrder.setCellData(ds_containerDoorOrder.getRowPosition() || 0, "bkNo", ed_bkNo.getValue());
        }

        await $c.sbm.execute(sbm_save);
        await $c.gus.cfAlertMsg(E_MSG_CM_INF_001); //  성공적으로 저장하였습니다.
    } else {
        await $c.gus.cfAlertMsg(E_MSG_CM_WRN_011, ["House B/L"]); // 이미 존재하는 @입니다.
    }
    scwin.f_Set("SAVE");
    cnd_ed_bkNo.setValue(ed_bkNo.getValue());
    await scwin.f_Retrieve();
};

scwin.undoAll = function (dltObj) {
    // dltObj.setBroadcast(false);
    for (let idx = dltObj.getRowCount() - 1; idx >= 0; --idx) {
        if (dltObj.getRowStatus(idx) == "C") {
            dltObj.removeRow(idx);
        } else {
            dltObj.undoRow(idx);
        }
    }
    // dltObj.setBroadcast(true, true);
};

scwin.f_Cancel = function () {
    if (scwin.statusFlag == "C") {
        scwin.f_Set("INIT");
    } else {
        scwin.f_Set("RETRIEVE");
        scwin.undoAll(ds_containerBookingList);
        scwin.undoAll(ds_ctrtNo);
        scwin.f_cancelRow(1);
        scwin.f_cancelRow(2);
        scwin.f_cancelRow(3);
        cnd_ed_bkNo.focus();
        scwin.processFlag = "T";
    }
};

scwin.f_Copy = function () {
    scwin.f_Set("CREATE");
    cnd_ed_bkNo.setValue("");

    // dataset clear
    ds_containerDoorOrder.removeAll();
    ds_containerDoorOrderQty.removeAll();
    ds_containerBookingCont.removeAll();
    ds_houseblList.removeAll();
    ds_ctrtNo.removeAll();
    scwin.f_Check();

    if (ds_containerBookingList.getRowCount() != 0) {
        ds_containerBookingList.modifyRowStatus(ds_containerBookingList.getRowPosition(), "C");  // insert 로 변경.
    }
    ed_bkNo.setValue("");
    ed_custCd.setValue("");
    ed_custNm.setValue("");
    ed_salesCd.setValue("");
    ed_salesNm.setValue("");

    tab1.setSelectedTabIndex(0);  // 1번째 탭으로 이동.
    //ed_reDt.focus();

};

scwin.f_Delete = async function () {
    scwin.flag = "DELETE";
    //bulk booking 마감 여부.
    if (ds_containerBookingList.getCellData(0, "cfs") == "B") {
        let param1 = hd_kcomcd.getValue();
        let param2 = cnd_ed_bkNo.getValue();
        dma_bkCloseCheck.set("sysCd", "SeaImportBookingEBC");
        dma_bkCloseCheck.set("queryId", "retrivebkCloseCheck");
        dma_bkCloseCheck.set("param1", param1);
        dma_bkCloseCheck.set("param2", param2);
        await $c.sbm.execute(sbm_bkCloseCheck);
        if (ds_bkCloseCheck.getCellData(0, "CODE") == "Y") {
            await $c.win.alert("Bring to a close");
            return;
        }
    }

    //send date  check
    let checked = 0;
    let errorChk = 0;
    for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
        if (ds_containerDoorOrder.getCellData(i, "sendDt") != "") {
            await $c.win.alert("Order sended : Order No -> " + ds_containerDoorOrder.getCellData(i, "bkNo") + ",Seq -> " + ds_containerDoorOrder.getCellData(i, "bkdoorseq"));
            errorChk = 1;
        }
        checked++;
    }
    if (errorChk == "1") {
        return;
    }

    // OC_BK_HBL 에 HBLNO CHECK
    scwin.f_RetrieveBinding(dma_retrieve, "RetrieveBookingHbl");
    await $c.sbm.execute(sbm_retrievebookingHbl);
    if (ds_bookingHbl.getCellData(0, "hblno") != "undefined" && ds_bookingHbl.getRowCount() != 0) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["House B/L", "delete"]);  // @은(는) @할 수 없습니다. // 
        return;
    }

    if (await $c.win.confirm(E_MSG_CM_CRM_004)) {  //삭제하시겠습니까?
        ds_containerBookingList.removeAll();  // 전체삭제.

        // OC_BK_HBL 에 HBLNO CHECK
        scwin.f_RetrieveBinding(dma_retrieve, "RetrieveBookingHbl");
        $c.sbm.execute(sbm_retrievebookingHbl);

        // 삭제
        $c.sbm.execute(sbm_delete);

        cnd_ed_bkNo.setValue("");
        //  그리드 초기화
        ds_containerBookingList.removeAll();
        ds_containerDoorOrder.removeAll();
        ds_containerDoorOrderQty.removeAll();
        ds_containerBookingCont.removeAll();
        ds_houseblList.removeAll();

        scwin.f_Set("INIT");
        cnd_ed_bkNo.setValue("");
    }
};

scwin.f_orderSend = async function () {
    if (ds_containerDoorOrder.getCellData(ds_containerDoorOrder.getRowPosition() || 0, "internalTyp") == "1") {
        // door order qty시 필수.
        if (ed_itemCd.getValue() == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Item"]); //@는 필수입력항목입니다.
            tab1.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
            ed_itemCd.focus();
            return;
        }

        let checked = 0;
        let errorChk = 0;

        // chk not check
        let j = 0;
        for (let i = 0; i <= ds_containerDoorOrder.getRowCount(); i++) {
            if (ds_containerDoorOrder.getCellData(i, "chk") == "T") {
                j = j + 1;
            }
            checked++;
        }
        if (j == 0) errorChk = 1;	 // chk를 선택안함.

        // order sended check
        for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
            if (ds_containerDoorOrder.getCellData(i, "chk") == "T") {
                let v_orderno = "";
                let v_seq = "";
                v_kcomcd = hd_kcomcd.getValue();
                v_orderno = ds_containerDoorOrder.getCellData(i, "bkNo");
                v_seq = ds_containerDoorOrder.getCellData(i, "bkdoorseq");
                dma_doorOrderQtyCheck.set("sysCd", "SeaImportBookingEBC");
                dma_doorOrderQtyCheck.set("queryId", "retrivebkCloseCheck");
                dma_doorOrderQtyCheck.set("param1", v_kcomcd);
                dma_doorOrderQtyCheck.set("param2", v_orderno);
                dma_doorOrderQtyCheck.set("param3", v_seq);

                await $c.sbm.execute(sbm_doorOrderQtyCheck);
                if (ds_doorOrderQtyCheck.getCellData(ds_doorOrderQtyCheck.getRowPosition(), "code") == "0") {
                    errorChk = 1;
                    await $c.win.alert("Door Order Qty is not exist: Order No -> " + v_orderno + ",Seq -> " + v_seq);
                }
            }
            checked++;
        }
        if (errorChk == "0") { //error가 없으면
            // order sended 실행.
            let checked = 0;
            for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
                if (ds_containerDoorOrder.getCellData(i, "chk") == "T") {
                    ds_containerDoorOrder.getCellData(i, "kcomcd", hd_kcomcd.getValue());
                    if (ds_containerDoorOrder.getCellData(i, "sendDt") == "") {
                        ds_containerDoorOrder.setCellData(i, "orderType", "1"); // Order Send
                    } else {
                        ds_containerDoorOrder.setCellData(i, "orderType", "2"); // Order Send
                    }
                    ds_containerDoorOrder.setCellData(i, "inpid", scwin.userId);


                }
                checked++;
            }
        }
        await $c.sbm.execute(sbm_saveOrderSend);
        await $c.gus.cfAlertMsg(E_MSG_CM_INF_001); //  성공적으로 저장하였습니다.
        await scwin.f_Retrieve();
    } else {
        await $c.win.alert("Normal Type");
        return;
    }
};

scwin.f_orderSendDel = async function () {
    if (ds_containerDoorOrder.getCellData(ds_containerDoorOrder.getRowPosition(), "internalTyp") == "1") {
        // order sended check
        let checked = 0;
        let errorChk = 0;

        // chk not check
        let j = 0;
        for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
            if (ds_containerDoorOrder.getCellData(i, "chk") == "T") {
                j = j + 1;
            }
            checked++;
        }
        if (j == 0) {
            errorChk = 1;	 // chk를 선택안함.
        }

        //send date  check
        j = 0;
        for (let i = 0; i <= ds_containerDoorOrder.getRowCount(); i++) {
            if (ds_containerDoorOrder.getCellData(i, "chk") == "T") {
                if (ds_containerDoorOrder.getCellData(i, "sendDt") == "") {
                    await $c.win.alert("Order is not sended : Order No -> " + ds_containerDoorOrder.getCellData(i, "bkNo") + ",Seq -> " + ds_containerDoorOrder.getCellData(i, "bkdoorseq"));
                    errorChk = 1;
                }
            }
            checked++;
        }

        for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
            if (ds_containerDoorOrder.getCellData(i, "chk") == "T") {
                if (ds_containerDoorOrder.getCellData(i, "mcomOdrNo") != "") {
                    await $c.win.alert("Order sended : Order No -> " + ds_containerDoorOrder.getCellData(i, "bkNo") + ",Seq -> " + ds_containerDoorOrder.getCellData(i, "bkdoorseq"));
                    errorChk = 1;
                }
            }
            checked++;
        }
        if (errorChk == "0") { //error가 없으면
            // order sended 실행.
            let checked = 0;
            for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
                if (ds_containerDoorOrder.getCellData(i, "chk") == "T") {
                    ds_containerDoorOrder.setCellData(i, "kcomcd", hd_kcomcd.getValue());
                    ds_containerDoorOrder.setCellData(i, "orderType", 3); // Order Send	Del
                    ds_containerDoorOrder.setCellData(i, "inpid", scwin.userId);
                }
                checked++;
            }
        }
        await $c.sbm.execute(sbm_saveOrderSend);
        await $c.gus.cfAlertMsg(E_MSG_CM_INF_001); //  성공적으로 저장하였습니다.
        await scwin.f_Retrieve();
    } else {
        await $c.win.alert("Normal Type");
        return;
    }
};

scwin.f_addRow = async function (disGubun) {
    switch (disGubun) {
        case 1:  	// Container Booking Door order
            if (ed_bkNo.getValue() == "") {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Booking Header"]);  // @은(는) 필수 입력 항목입니다.
            } else {
                let idx = ds_containerDoorOrder.insertRow();
                // gr_containerDoorOrder.setCellDisplayFormat(idx, "doordt", "yyyy/MM/dd-HH:mm");
                let v_seq = ds_containerDoorOrder.getRowCount().toString();
                let v_seqResult = v_seq.padStart(2, "0");
                ds_containerDoorOrder.setCellData(idx, "bkdoorseq", v_seqResult);
                ds_containerDoorOrder.setCellData(idx, "kcomcd", hd_kcomcd.getValue());
                ds_containerDoorOrder.setCellData(idx, "bkNo", ed_bkNo.getValue()); //update일때.
                ds_containerDoorOrder.setCellData(idx, "internalTyp", "1");
                ds_containerDoorOrder.setCellData(idx, "inpid", scwin.userId);
                ds_containerDoorOrder.setCellData(idx, "doordt", ed_bkEta.getValue() + scwin.currentTime);
                gr_containerDoorOrder.setFocusedCell(idx, gr_containerDoorOrder.getFocusedColumnIndex() ?? 0, false);
            }
            break;

        case 2:  	// Container Booking Door order Qty
            if (ed_bkNo.getValue() == "") {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Booking Header"]);  // @은(는) 필수 입력 항목입니다.
            } else {
                // Door order Seq 미입력시 Door order Qty addition시 alert
                if (ds_containerDoorOrder.getCellData(ds_containerDoorOrder.getRowPosition(), "bkdoorseq") == "" || ds_containerDoorOrder.getRowCount() == 0) {
                    await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Booking Door Order"]); // @이(가) 존재하지 않습니다.
                } else {
                    idx = ds_containerDoorOrderQty.insertRow();
                    ds_containerDoorOrderQty.setCellData(idx, "kcomcd", hd_kcomcd.getValue());
                    ds_containerDoorOrderQty.setCellData(idx, "bkNo", ed_bkNo.getValue()); //update일때.
                    ds_containerDoorOrderQty.setCellData(idx, "bkdoorseq", ds_containerDoorOrder.getCellData(ds_containerDoorOrder.getRowPosition(), "bkdoorseq"));  //update일때.
                    ds_containerDoorOrderQty.setCellData(idx, "inpid", scwin.userId);
                    ds_containerDoorOrderQty.setCellData(idx, "qty", "0");
                    gr_containerDoorOrderQty.setFocusedCell(idx, gr_containerDoorOrderQty.getFocusedColumnIndex() ?? 0, false);
                }
            }
            break;

        case 3:  	// Container
            if (ed_bkNo.getValue() == "") {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Booking Header"]);  // @은(는) 필수 입력 항목입니다.
            } else {
                // Door order Seq 미입력시 Container addition시 alert
                if (ds_containerDoorOrder.getCellData(ds_containerDoorOrder.getRowPosition(), "bkdoorseq") == "" || ds_containerDoorOrder.getRowCount() == 0) {
                    await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Booking Door Order"]); // @이(가) 존재하지 않습니다.
                } else {
                    idx = ds_containerBookingCont.insertRow();
                    ds_containerBookingCont.setCellData(idx, "kcomcd", hd_kcomcd.getValue());
                    ds_containerBookingCont.setCellData(idx, "bkNo", ed_bkNo.getValue()); //update일때.
                    ds_containerBookingCont.setCellData(idx, "bkdoorseq", ds_containerDoorOrder.getCellData(ds_containerDoorOrder.getRowPosition(), "bkdoorseq"));  //update일때.
                    ds_containerBookingCont.setCellData(idx, "inpid", scwin.userId);
                    ds_containerBookingCont.setCellData(idx, "cntpkg", ed_pkg.getValue());
                    ds_containerBookingCont.setCellData(idx, "cntwgt", "0");
                    ds_containerBookingCont.setCellData(idx, "cntmsrt", "0");
                    gr_containerBookingCont.setFocusedCell(idx, gr_containerBookingCont.getFocusedColumnIndex() ?? 0, false);
                }
            }
            break;
    }
};

scwin.f_deleteRow = async function (disGubun) {
    let row;
    switch (disGubun) {
        case 1:  	// Container Booking Door order
            if (ds_containerDoorOrderQty.getRowCount() > 0 || ds_containerBookingCont.getRowCount() > 0) {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["Door Order Quantity Or Container", "delete"]);  // @은(는) @할 수 없습니다.
            } else if (ds_containerDoorOrder.getCellData(ds_containerDoorOrder.getRowPosition(), "sendDt") != "") {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["Order sended", "delete"]);  // @은(는) @할 수 없습니다.
            } else {
                row = gr_containerDoorOrder.getFocusedRowIndex();
                scwin.deleteRow(ds_containerDoorOrder, row);
                if (row >= ds_containerDoorOrder.getRowCount()) {
                    row = ds_containerDoorOrder.getRowCount() - 1;
                }
                gr_containerDoorOrder.setFocusedCell(row, gr_containerDoorOrder.getFocusedColumnIndex() ?? 0, false);
            }
            break;

        case 2:  	// Container Booking Door order Qty
            row = gr_containerDoorOrderQty.getFocusedRowIndex();
            scwin.deleteRow(ds_containerDoorOrderQty, row);
            if (row >= ds_containerDoorOrderQty.getRowCount()) {
                row = ds_containerDoorOrderQty.getRowCount() - 1;
            }
            gr_containerDoorOrderQty.setFocusedCell(row, gr_containerDoorOrderQty.getFocusedColumnIndex() ?? 0, false);
            break;

        case 3:  	// Container
            row = gr_containerBookingCont.getFocusedRowIndex();
            scwin.deleteRow(ds_containerBookingCont, row);
            if (row >= ds_containerBookingCont.getRowCount()) {
                row = ds_containerBookingCont.getRowCount() - 1;
            }
            gr_containerBookingCont.setFocusedCell(row, gr_containerBookingCont.getFocusedColumnIndex() ?? 0, false);
            break;

        default:
            break;
    }
};

scwin.f_cancelRow = function (disGubun) {
    let row;
    switch (disGubun) {
        case 1:  	//Door Order
            row = gr_containerDoorOrder.getFocusedRowIndex();
            scwin.undoAll(ds_containerDoorOrder);
            scwin.undoAll(ds_containerDoorOrderQty);
            if (row >= ds_containerDoorOrder.getRowCount()) {
                row = ds_containerDoorOrder.getRowCount() - 1;
            }
            break;

        case 2:  // Door Order Qty
            row = gr_containerDoorOrderQty.getFocusedRowIndex();
            scwin.undoAll(ds_containerDoorOrderQty);
            if (row >= ds_containerDoorOrderQty.getRowCount()) {
                row = ds_containerDoorOrderQty.getRowCount() - 1;
            }
            break;

        case 3:  // Container
            row = gr_containerBookingCont.getFocusedRowIndex();
            scwin.undoAll(ds_containerBookingCont);
            if (row >= ds_containerBookingCont.getRowCount()) {
                row = ds_containerBookingCont.getRowCount() - 1;
            }
            break;

        default:
            break;
    }
};

scwin.f_validate = async function () {
    let tabIndex = tab1.getSelectedTabIndex();
    if (tabIndex == 0) {
        if (!await scwin.f_BookingTabValidate()) {
            return false;
        }
    } else if (tabIndex == 1) {
        if (!await scwin.f_DoorOrderTabValidate()) {
            return false;
        }
    }
    return true;
};

scwin.f_BookingTabValidate = async function () {
    if (!await $c.gus.cfValidate([ed_reDt, ed_bkEtd, ed_bkEta])) {  //validExp 가 yes일때 check
        return false;
    }

    if (ed_bkEtd.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["ETD"]); //@는 필수입력항목입니다.
        //cfViewTab(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
        ed_bkEtd.focus();
        return false;
    }
    if (ed_bkEta.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["ETA"]); //@는 필수입력항목입니다.
        //cfViewTab(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
        ed_bkEta.focus();
        return false;
    }

    // 날짜 범위 확인
    if (!await $c.gus.cfIsAfterDate(ed_bkEtd.getValue(), ed_bkEta.getValue())) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_048, new Array("ETD", "ETA"));  //@은(는) 보다 작아야 합니다.
        ed_bkEtd.focus();
        return false;
    }

    // Container Type dual check
    if (!await scwin.f_containerDualCheck()) {
        return false;
    }
    // Container Type value check
    if (ed_cnttype1.getValue() != "") {
        let STR = ds_containerType.getMatchedIndex("code", ed_cnttype1.getValue());
        if (STR.length == 0) {  // 값이 없을때
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Container Type"]); // @이(가) 존재하지 않습니다.
            //cfViewTab(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
            ed_cnttype1.focus();
            return false;
        }
    }

    // Container Type value check
    if (ed_cnttype2.getValue() != "") {
        let STR = ds_containerType.getMatchedIndex("code", ed_cnttype2.getValue());
        if (STR.length == 0) {  // 값이 없을때
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Container Type"]); // @이(가) 존재하지 않습니다.
            //cfViewTab(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
            ed_cnttype2.focus();
            return false;
        }
    }

    // Container Type value check
    if (ed_cnttype3.getValue() != "") {
        let STR = ds_containerType.getMatchedIndex("code", ed_cnttype3.getValue());
        if (STR.length == 0) {  // 값이 없을때
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Container Type"]); // @이(가) 존재하지 않습니다.
            //cfViewTab(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
            ed_cnttype3.focus();
            return false;
        }
    }

    // Container Type value check
    if (ed_cnttype4.getValue() != "") {
        let STR = ds_containerType.getMatchedIndex("code", ed_cnttype4.getValue());
        if (STR.length == 0) {  // 값이 없을때
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Container Type"]); // @이(가) 존재하지 않습니다.
            //cfViewTab(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
            ed_cnttype4.focus();
            return false;
        }
    }

    // Customer check
    if (ed_custCd.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Customer"]); //@는 필수입력항목입니다.
        //cfViewTab(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
        ed_custCd.focus();
        return false;
    }

    // Contract No Null Check
    if (ds_ctrtNo.getCellData(ds_ctrtNo.getRowPosition(), "ctrtNo") == "선택" || lc_contractno.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Contract No"]); //@는 필수입력항목입니다.
        //cfViewTab(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
        ed_custCd.focus();
        return false;
    }

    //dept		2019.04.08 최우성 대리 요청사항: 필수입력 체크 해제
    // 		if(ed_dept.getValue() == ""){
    // 			cfAlertMsg(E_MSG_CM_ERR_002, ["Department"]); //@는 필수입력항목입니다.
    // 	    	//cfViewTab(0);  // 1번째 탭으로 이동.  ed_dept.focus() 잡아주기 위함.
    // 			ed_dept.focus();
    // 			return false;
    // 		}

    return true;
};

scwin.f_DoorOrderTabValidate = async function () {
    let msg = "[Booking] ";
    if (!$c.gus.cfValidate([gr_containerDoorOrder])) {  //validExp 가 yes일때 check
        return false;
    }

    if (ed_bkEtd.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, [msg + "ETD"]); //@는 필수입력항목입니다.
        //ed_bkEtd.focus();
        return false;
    }
    if (ed_bkEta.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, [msg + "ETA"]); //@는 필수입력항목입니다.
        //ed_bkEta.focus();
        return false;
    }

    // 날짜 범위 확인
    if (!$c.gus.cfIsAfterDate(ed_bkEtd.getValue(), ed_bkEta.getValue())) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_048, new Array("ETD", "ETA"));  //@은(는) 보다 작아야 합니다.
        //ed_bkEtd.Focus();
        return false;
    }

    // Container Type dual check
    if (!await scwin.f_containerDualCheck()) {
        return false;
    }

    // Container Type value check
    if (ed_cnttype1.getValue() != "") {
        STR = ds_containerType.getMatchedIndex("code", ed_cnttype1.getValue());
        if (STR.length == 0) {  // 값이 없을때
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, [msg + "Container Type"]); // @이(가) 존재하지 않습니다.
            //ed_cnttype1.focus();
            return false;
        }
    }

    // Container Type value check
    if (ed_cnttype2.getValue() != "") {
        let STR = ds_containerType.getMatchedIndex("code", ed_cnttype2.getValue());
        if (STR.length == 0) {  // 값이 없을때
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, [msg + "Container Type"]); // @이(가) 존재하지 않습니다.
            //ed_cnttype2.focus();
            return false;
        }
    }

    // Container Type value check
    if (ed_cnttype3.getValue() != "") {
        let STR = ds_containerType.getMatchedIndex("code", ed_cnttype3.getValue());
        if (STR.length == 0) {  // 값이 없을때
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, [msg + "Container Type"]); // @이(가) 존재하지 않습니다.
            //ed_cnttype3.focus();
            return false;
        }
    }

    // Container Type value check
    if (ed_cnttype4.getValue() != "") {
        let STR = ds_containerType.getMatchedIndex("code", ed_cnttype4.getValue());
        if (STR.length == 0) {  // 값이 없을때
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, [msg + "Container Type"]); // @이(가) 존재하지 않습니다.
            //ed_cnttype4.focus();
            return false;
        }
    }

    // Customer check
    if (ed_custCd.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, [msg + "Customer"]); //@는 필수입력항목입니다.
        //ed_custCd.focus();
        return false;
    }

    // Contract No Null Check
    if (ds_ctrtNo.getCellData(ds_ctrtNo.getRowPosition() || 0, "ctrtNo") == "선택" || $c.util.isEmpty(lc_contractno.getValue())) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, [msg + "Contract No"]); //@는 필수입력항목입니다.
        //ed_custCd.focus();
        return false;
    }

    //dept
    if (ed_dept.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, [msg + "Department"]); //@는 필수입력항목입니다.
        //ed_dept.focus();
        return false;
    }

    // Door order 등록시 Door order Qty 필수
    for (let i = 0; i <= ds_containerDoorOrder.getRowCount(); i++) {
        if (ds_containerDoorOrder.getRowStatus(i) != "C") {
            if (ds_containerDoorOrder.getRowCount() > 0) {
                if (ds_containerDoorOrderQty.getRowCount() == 0) {
                    await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Door Order Qty"]); //@는 필수입력항목입니다.
                    return false;
                }
            }
        }
    }

    // Door order Seq check
    for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
        if (ds_containerDoorOrder.getCellData(i, "bkdoorseq") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Door Order Seq"]); //@는 필수입력항목입니다.
            gr_containerDoorOrder.setFocusedCell(i, "bkdoorseq", true);
            return false;
        }
    }

    // Container Order Date check
    for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
        if (ds_containerDoorOrder.getCellData(i, "doordt") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Container Order Date"]); //@는 필수입력항목입니다.
            gr_containerDoorOrder.setFocusedCell(i, "doordt", true);
            return false;
        }
    }

    // Container Order Trucker check
    for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
        if (ds_containerDoorOrder.getCellData(i, "transcd") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Container Order Trucker"]); //@는 필수입력항목입니다.
            gr_containerDoorOrder.setFocusedCell(i, "transcd", true);
            return false;
        }
    }

    //Door order Qty Container Type check
    for (let i = 0; i < ds_containerDoorOrderQty.getRowCount(); i++) {
        if (ds_containerDoorOrderQty.getCellData(i, "qtytype") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Door Order Container Type"]); //@는 필수입력항목입니다.
            gr_containerDoorOrder.setFocusedCell(i, "qtytype", true);
            return false;
        }
    }

    // Container No check
    for (let i = 0; i < ds_containerBookingCont.getRowCount(); i++) {
        if (ds_containerBookingCont.getCellData(i, "cntno") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Container No"]); //@는 필수입력항목입니다.
            gr_containerDoorOrder.setFocusedCell(i, "cntno", true);
            return false;
        }
    }

    return true;
};

