scwin.f_openPgm = function (name) {
    let strPath = "";
    let paramObj = {};
    let menuNm = "";
    let menuId = "";
    if (name == "BookingFind") {
        strPath = "/ui/il/seaout/sobk/se_103_01_01b.xml";
        menuId = "se_103_01_01b.jsp";
        menuNm = "Booking Search";
        paramObj = {
            hhio: hd_bkIo.getValue(),
            menuInfo: {
                menuParam: {
                    hhio: hd_bkIo.getValue(),
                }
            }
        }
    } else if (name == "BulkBl") {
        //개발대상에서 제외된 화면이라 막음
        return;
        strPath = "/ui/il/seainb/sibl/se_203_01_01b.xml";
        menuId = "se_201_01_01b";
        menuNm = "Import Bulk B/L";
        paramObj.pgmInfo = {
            linkcheck: "4"
            , kcomcd: hd_kcomcd.getValue()
            , bkno: cnd_ed_bkNo.getValue()
        }
    } else if (name == "HouseBl") {
        strPath = "/ui/il/seainb/sibl/se_201_01_01b.xml";
        menuId = "se_201_01_01b.jsp";
        menuNm = "Import House B/L";
        paramObj = {
            linkcheck: "4"
            , kcomcd: hd_kcomcd.getValue()
            , bkno: cnd_ed_bkNo.getValue()
        }
    }
    $c.win.openMenu(menuNm, strPath, menuId, paramObj, { openAction: "exist" });
};

scwin.f_ContractInfo = async function () {
    ds_ctrtNo.removeAll();
    if (lc_cfs.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Cargo Type"]); //@는 필수입력항목입니다.
        return;
    }
    dma_retrieveCtrtClnt.setEmptyValue();
    dma_retrieveCtrtClnt.set("ctrtNo", scwin.v_contractno);
    dma_retrieveCtrtClnt.set("ctrtClntNo", ed_custCd.getValue());
    dma_retrieveCtrtClnt.set("scDate", ed_bkEta.getValue());
    dma_retrieveCtrtClnt.set("ctrtDtYn", 1);	 //계약기간 여부
    dma_retrieveCtrtClnt.set("ctrtDistrictCd", "ZZA");	 // ZZA : 해운권역 , ZZB : 항공권역
    dma_retrieveCtrtClnt.set("impExpDomesticClsCd", "I"); // in/out
    if (lc_cfs.getValue() != "B") {
        dma_retrieveCtrtClnt.set("bizDivCntrYn", "1"); //container
    } else {
        dma_retrieveCtrtClnt.set("bizDivBulkYn", "1"); // bulk
    }
    await $c.sbm.execute(sbm_retrieveCtrtClnt);
    if (ds_ctrtNo.getTotalRow() > 1) lc_contractno.setSelectedIndex(-1);
    arr = ds_ctrtNo.getAllJSON();
    arr.sort(function (a, b) {
        if (a.ctrtNo === "선택") return -1;
        if (b.ctrtNo === "선택") return 1;
        return 0;
    });

    ds_ctrtNo.setJSON(arr);
};

scwin.f_doorTypeQtyLoading = function (row, colid) {
    let wgt = Number(ed_wgt.getValue()) / 1000;
    let msr = Number(ed_msr.getValue());
    if (ds_containerDoorOrderQty.getCellData(ds_containerDoorOrderQty.getRowPosition(), "qtytype") == "WGT" || ds_containerDoorOrderQty.getCellData(ds_containerDoorOrderQty.getRowPosition(), "qtytype") == "M/T") {
        ds_containerDoorOrderQty.setCellData(ds_containerDoorOrderQty.getRowPosition(), "qty", ed_wgt.getValue());
    } else if (ds_containerDoorOrderQty.getCellData(ds_containerDoorOrderQty.getRowPosition(), "qtytype") == "R/T") {
        if (wgt > msr) {
            ds_containerDoorOrderQty.setCellData(ds_containerDoorOrderQty.getRowPosition(), "qty", wgt);
        } else {
            ds_containerDoorOrderQty.setCellData(ds_containerDoorOrderQty.getRowPosition(), "qty", msr);
        }
    } else if (ds_containerDoorOrderQty.getCellData(ds_containerDoorOrderQty.getRowPosition(), "qtytype") == "CBM") {
        ds_containerDoorOrderQty.setCellData(ds_containerDoorOrderQty.getRowPosition(), "qty", msr);
    } else {
        if (ds_containerDoorOrderQty.getCellData(ds_containerDoorOrderQty.getRowPosition(), "qtytype") == ed_cnttype1.getValue()) {
            ds_containerDoorOrderQty.setCellData(ds_containerDoorOrderQty.getRowPosition(), "qty", ed_cntqty1.getValue());
        } else if (ds_containerDoorOrderQty.getCellData(ds_containerDoorOrderQty.getRowPosition(), "qtytype") == ed_cnttype2.getValue()) {
            ds_containerDoorOrderQty.setCellData(ds_containerDoorOrderQty.getRowPosition(), "qty", ed_cntqty2.getValue());
        } else if (ds_containerDoorOrderQty.getCellData(ds_containerDoorOrderQty.getRowPosition(), "qtytype") == ed_cnttype3.getValue()) {
            ds_containerDoorOrderQty.setCellData(ds_containerDoorOrderQty.getRowPosition(), "qty", ed_cntqty3.getValue());
        } else if (ds_containerDoorOrderQty.getCellData(ds_containerDoorOrderQty.getRowPosition(), "qtytype") == ed_cnttype4.getValue()) {
            ds_containerDoorOrderQty.setCellData(ds_containerDoorOrderQty.getRowPosition(), "qty", ed_cntqty4.getValue());
        }
    }
};

scwin.f_containerGridTypeLoading = function () {
    let cnt1 = "0";
    let cnt2 = "0";
    let cnt3 = "0";
    let cnt4 = "0";
    if (lc_cfs.getValue() != "B") {
        if (ed_cnttype1.getValue() != "" && ed_cntqty1.getValue() != "0") {
            cnt1 = ed_cnttype1.getValue();
        }

        if (ed_cnttype2.getValue() != "" && ed_cntqty2.getValue() != "0") {
            cnt2 = ed_cnttype2.getValue();
        }

        if (ed_cnttype3.getValue() != "" && ed_cntqty3.getValue() != "0") {
            cnt3 = ed_cnttype3.getValue();
        }

        if (ed_cnttype4.getValue() != "" && ed_cntqty4.getValue() != "0") {
            cnt4 = ed_cnttype4.getValue();
        }
    }
    let newQuery = `${cnt1};${cnt2};${cnt3};${cnt4};`;
    if (newQuery === scwin.containerGridTypeQuery) {
        return;
    }
    scwin.containerGridTypeQuery = newQuery;
    dma_containerGridType.set("sysCd", "SeaImportBookingEBC");
    dma_containerGridType.set("queryId", "retriveTypeList");
    dma_containerGridType.set("param1", cnt1);
    dma_containerGridType.set("param2", cnt2);
    dma_containerGridType.set("param3", cnt3);
    dma_containerGridType.set("param4", cnt4);
    $c.sbm.execute(sbm_containerGridType);
};

scwin.f_containerTypeLoading = function () {
    dma_containerType.set("sysCd", "ilCommonEBC");
    dma_containerType.set("queryId", "retriveContainerTypeList");
    $c.sbm.execute(sbm_containerType);
};

scwin.f_containerDualCheck = async function () {
    let v_containerCheck = true;
    if (ed_cnttype1.getValue() != "" && ed_cnttype2.getValue() != "" && ed_cnttype1.getValue() == ed_cnttype2.getValue()) {
        v_containerCheck = false;
    } else if (ed_cnttype1.getValue() != "" && ed_cnttype3.getValue() != "" && ed_cnttype1.getValue() == ed_cnttype3.getValue()) {
        v_containerCheck = false;
    } else if (ed_cnttype1.getValue() != "" && ed_cnttype4.getValue() != "" && ed_cnttype1.getValue() == ed_cnttype4.getValue()) {
        v_containerCheck = false;
    } else if (ed_cnttype2.getValue() != "" && ed_cnttype3.getValue() != "" && ed_cnttype2.getValue() == ed_cnttype3.getValue()) {
        v_containerCheck = false;
    } else if (ed_cnttype2.getValue() != "" && ed_cnttype4.getValue() != "" && ed_cnttype2.getValue() == ed_cnttype4.getValue()) {
        v_containerCheck = false;
    } else if (ed_cnttype3.getValue() != "" && ed_cnttype4.getValue() != "" && ed_cnttype3.getValue() == ed_cnttype4.getValue()) {
        v_containerCheck = false;
    }
    if (!v_containerCheck) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_032, Array("Container Type")); //  @은(는) 중복될 수 없습니다.
    }
    return v_containerCheck;
};

