scwin.gr_houseblList_oncelldblclick = function (row, columnIndex, columnId) {
    let menuNm = "Import House B/L";
    let src = "/ui/il/seainb/sibl/se_201_01_01b.xml";
    let menuId = "se_201_01_01b.jsp";
    let paramObj = {
        linkcheck: "1"
        , kcomcd: hd_kcomcd.getValue()
        , mhno: ds_houseblList.getCellData(row, "mhno")
    };

    if (ds_houseblList.getCellData(row, "autono") == "DIRECT" && ds_houseblList.getCellData(row, "hhbltype") == "B") {  //Bulk
        //개발대상에서 제외된 화면이라 막음
        return;
        src = "/ui/il/seainb/sibl/se_203_01_01b.xml";
        menuId = "se_203_01_01b";
        menuNm = "Import Bulk B/L";
    } else {  //House
        paramObj.blno = ds_houseblList.getCellData(row, "hhblno");
    }

    $c.win.openMenu(menuNm, src, menuId, paramObj, { openAction: "exist" });
};

scwin.gr_containerDoorOrder_onviewchange = async function (info) {
    if (info.colId == "bkdoorseq") {
        let value = info.newValue;
        for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
            if (i == info.rowIndex) {
                continue;
            }
            if (value == ds_containerDoorOrder.getCellData(i, "bkdoorseq")) {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_032, Array("Container Seq")); //  @은(는) 중복될 수 없습니다.
                gr_containerDoorOrder.setFocusedCell(info.rowIndex, "bkdoorseq", true);
                return;
            }
        }
    }
};

scwin.gr_containerDoorOrder_ontextimageclick = function (row, columnIndex) {
    let colId = gr_containerDoorOrder.getColumnID(columnIndex);
    switch (colId) {
        case "transcd":
            if (ds_containerDoorOrder.getCellData(row, "internalTyp") == "1") {
                scwin.f_PopUpGrid("Department", row, "F");
            } else {
                scwin.f_PopUpGrid("Customer", row, "F");
            }
            break;

        case "fcity":
            scwin.f_PopUpGrid("PickupCy", row, "F");
            break;

        case "doorcd":
            scwin.f_PopUpGrid("Door", row, "F");
            break;

        case "tcity":
            scwin.f_PopUpGrid("GateinCy", row, "F");
