scwin.gr_containerDoorOrder_onafteredit = function (row, columnIndex, value) {
    let colId = gr_containerDoorOrder.getColumnID(columnIndex);
    switch (colId) {
        case "transcd":
            //코드값이 공백이 아닌경우 && 값이 변하였을경우 팝업을 호출한다.
            if (ds_containerDoorOrder.getCellData(row, colId).trim() != "") {
                if (ds_containerDoorOrder.getCellData(row, "internalTyp") == "1") {
                    ds_containerDoorOrder.setCellData(row, "transnm", "");
                    scwin.f_PopUpGrid("Department", row, "T");
                } else {
                    ds_containerDoorOrder.setCellData(row, "transnm", "");
                    scwin.f_PopUpGrid("Customer", row, "T");
                }
                //Name field 존재시 check.
                //Name Value 가 Blank 일경우 코드값을 Blank 한다.
            } else if (ds_containerDoorOrder.getCellData(row, colId).trim() == "") {
                ds_containerDoorOrder.setCellData(row, "transcd", "");
                ds_containerDoorOrder.setCellData(row, "transnm", "");
            }
            break;

        case "fcity":
            //코드값이 공백이 아닌경우 && 값이 변하였을경우 팝업을 호출한다.
            if (ds_containerDoorOrder.getCellData(row, colId).trim() != "") {
                ds_containerDoorOrder.setCellData(row, "fcitynm", "");
                scwin.f_PopUpGrid("PickupCy", row, "T");
                //Name field 존재시 check.
                //Name Value 가 Blank 일경우 코드값을 Blank 한다.
            } else if (ds_containerDoorOrder.getCellData(row, colId).trim() == "") {
                ds_containerDoorOrder.setCellData(row, "fcity", "");
                ds_containerDoorOrder.setCellData(row, "fcitynm", "");
            }
            break;

        case "doorcd":
            //코드값이 공백이 아닌경우 && 값이 변하였을경우 팝업을 호출한다.
            if (ds_containerDoorOrder.getCellData(row, colId).trim() != "") {
                ds_containerDoorOrder.setCellData(row, "doornm", "");
                scwin.f_PopUpGrid("Door", row, "T");
                //Name field 존재시 check.
                //Name Value 가 Blank 일경우 코드값을 Blank 한다.
            } else if (ds_containerDoorOrder.getCellData(row, colId).trim() == "") {
                ds_containerDoorOrder.setCellData(row, "doorcd", "");
                ds_containerDoorOrder.setCellData(row, "doornm", "");
            }
            break;

        case "tcity":
            //코드값이 공백이 아닌경우 && 값이 변하였을경우 팝업을 호출한다.
            if (ds_containerDoorOrder.getCellData(row, colId).trim() != "") {
                ds_containerDoorOrder.setCellData(row, "tcitynm", "");
                scwin.f_PopUpGrid("GateinCy", row, "T");
                //Name field 존재시 check.
                //Name Value 가 Blank 일경우 코드값을 Blank 한다.
            } else if (ds_containerDoorOrder.getCellData(row, colId).trim() == "") {
                ds_containerDoorOrder.setCellData(row, "tcity", "");
                ds_containerDoorOrder.setCellData(row, "tcitynm", "");
            }
            break;

        default:
            break;
    }
};

scwin.gr_containerDoorOrderQty_onviewchange = async function (info) {
    if (info.colId == "qtytype") {
        let value = info.newValue;
        for (let i = 0; i < ds_containerDoorOrderQty.getRowCount(); i++) {
            if (i == info.rowIndex) {
                continue;
            }
            if (value == ds_containerDoorOrderQty.getCellData(i, "qtytype")) {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_032, Array("Container Type")); //  @은(는) 중복될 수 없습니다.
                gr_containerDoorOrderQty.setFocusedCell(info.rowIndex, "qtytype", true);
                return;
            }
        }
    }
};

scwin.gr_containerDoorOrderQty_ontextimageclick = function (row, columnIndex) {
    let colId = gr_containerDoorOrderQty.getColumnID(columnIndex - 1);
    if (colId == "qtytype") {
        scwin.f_PopUpGrid("QtyType", row, "F");
    }
};

scwin.gr_containerDoorOrderQty_onbeforeedit = function (row, col, value) {
    let colid = gr_containerDoorOrderQty.getColumnID(col);
    if (colid !== "qtytype") {
        return;
    }
    scwin.grdSelectValue = value;
};

scwin.gr_containerDoorOrderQty_onafteredit = function (row, col, value) {
    let colid = gr_containerDoorOrderQty.getColumnID(col);
    if (colid == "qty") {
        if (value == "" || isNaN(value)) {
            ds_containerDoorOrderQty.setCellData(row, colid, "0");
        }
    } else if (colid == "qtytype") {
        if (value === "" && value !== scwin.grdSelectValue) {
            ds_containerDoorOrderQty.setCellData(row, colid, scwin.grdSelectValue);
        }
    }
};

