scwin.setDate = function (str) {
    if (str == "") return "";
    return scwin.formatDateTimeMask(str);
}

scwin.formatDateTimeMask = function (str) {
    if (!str) str = "";

    // 숫자만 남기기
    str = String(str).replace(/\D/g, "");

    // 최대 12자리까지만
    str = str.substring(0, 12);

    // 자리 채우기 (부족하면 공백)
    var full = str.padEnd(12, " ");

    return (
        full.substring(0, 4) + "/" +
        full.substring(4, 6) + "/" +
        full.substring(6, 8) + "-" +
        full.substring(8, 10) + ":" +
        full.substring(10, 12)
    );
}
